#!/usr/bin/env bats

# End-to-end harness: run the workflow through `act` against three fixture
# scenarios and assert exact output values for each. All act invocations
# happen in setup_file (one act run per case) so the per-test asserts
# below are cheap.
#
# Each case appends its captured output to act-result.txt in the project
# root, clearly delimited.

setup_file() {
    PROJECT_ROOT="$(cd "${BATS_TEST_DIRNAME}/.." && pwd)"
    export PROJECT_ROOT
    export ACT_RESULT_FILE="${PROJECT_ROOT}/act-result.txt"
    : > "${ACT_RESULT_FILE}"

    # Run each case once and stash output paths for the per-test asserts.
    _run_case "default"        "${PROJECT_ROOT}/tests/cases/default"
    _run_case "all-pass"       "${PROJECT_ROOT}/tests/cases/all-pass"
    _run_case "mixed-no-flaky" "${PROJECT_ROOT}/tests/cases/mixed-no-flaky"
}

# _run_case CASE_NAME FIXTURES_SRC
# Stages a temp git repo with the project + the case's fixture data, runs
# `act push --rm`, captures stdout+stderr to a per-case file, appends to
# act-result.txt, and writes the exit code to a sidecar file.
_run_case() {
    local case_name="$1"
    local fixtures_src="$2"
    local tmp out_file exit_file
    tmp="$(mktemp -d)"
    out_file="${PROJECT_ROOT}/.act-out-${case_name}.txt"
    exit_file="${PROJECT_ROOT}/.act-exit-${case_name}.txt"

    # Stage project files (excluding the existing git repo and prior outputs).
    rsync -a \
        --exclude='.git' \
        --exclude='act-result.txt' \
        --exclude='.act-out-*.txt' \
        --exclude='.act-exit-*.txt' \
        "${PROJECT_ROOT}/" "${tmp}/"

    # Replace fixtures/ with this case's data.
    rm -rf "${tmp}/fixtures"
    cp -r "${fixtures_src}" "${tmp}/fixtures"

    # Initialize a git repo so act can resolve HEAD.
    (
        cd "${tmp}"
        git init -q -b main
        git -c user.email=t@example.com -c user.name=harness add -A
        git -c user.email=t@example.com -c user.name=harness commit -q -m "case ${case_name}"
    )

    # Run act. The .actrc selects act-ubuntu-pwsh:latest as the runner image.
    local rc=0
    (
        cd "${tmp}"
        act push --rm 2>&1
    ) > "${out_file}" || rc=$?
    echo "${rc}" > "${exit_file}"

    # Append clearly-delimited output to act-result.txt.
    {
        printf '\n=========================================================\n'
        printf 'CASE: %s\n' "${case_name}"
        printf 'FIXTURES: %s\n' "${fixtures_src}"
        printf 'EXIT: %d\n' "${rc}"
        printf '=========================================================\n'
        cat "${out_file}"
        printf '\n--------- end %s ---------\n' "${case_name}"
    } >> "${ACT_RESULT_FILE}"

    rm -rf "${tmp}"
}

# Helper for per-test asserts: read a case's output file.
_case_output() {
    cat "${PROJECT_ROOT}/.act-out-$1.txt"
}
_case_exit() {
    cat "${PROJECT_ROOT}/.act-exit-$1.txt"
}

# --- Common assertions ------------------------------------------------------

@test "act-result.txt was created" {
    [ -s "${ACT_RESULT_FILE}" ]
}

